order-image-slice:initial;border-image-width:initial;border-image-outset:initial;border-image-repeat:initial;}.nav-links a:hover{color:var(--text);border-top-color:rgba(255, 255, 255, 0.12);border-right-color:rgba(255, 255, 255, 0.12);border-bottom-color:rgba(255, 255, 255, 0.12);border-left-color:rgba(255, 255, 255, 0.12);background-image:initial;background-position-x:initial;background-position-y:initial;background-size:initial;background-repeat:initial;background-attachment:initial;background-origin:initial;background-clip:initial;background-color:rgba(255, 255, 255, 0.04);}.badge .dot{width:9px;height:9px;border-top-left-radius:999px;border-top-right-radius:999px;border-bottom-right-radius:999px;border-bottom-left-radius:999px;box-shadow:rgba(34, 197, 94, 0.18) 0px 0px 0px 4px;}h1{margin-top:0px;margin-right:0px;margin-bottom:10px;margin-left:0px;font-size:clamp(28px, 4vw, 44px);line-height:1.12;letter-spacing:0.2px;}.hero-card img{width:100%;height:260px;object-fit:cover;display:block;filter:saturate(1.05) contrast(1.05);}.hero-card .overlay{position:absolute;top:0px;right:0px;bottom:0px;left:0px;background-image:linear-gradient(to top, rgba(11, 18, 32, 0.88), rgba(11, 18, 32, 0.15) 60%, transparent);background-position-x:initial;background-position-y:initial;background-size:initial;background-repeat:initial;background-attachment:initial;background-origin:initial;background-clip:initial;background-color:initial;pointer-events:none;}.hero-card .info{position:absolute;left:16px;right:16px;bottom:16px;display:grid;row-gap:10px;column-gap:10px;}.price-pill strong{font-size:16px;}.price-pill span{color:var(--muted);font-weight:700;}.mini .chip{padding-top:10px;padding-right:10px;padding-bottom:10px;padding-left:10px;border-top-left-radius:14px;border-top-right-radius:14px;border-bottom-right-radius:14px;border-bottom-left-radius:14px;border-top-width:1px;border-right-width:1px;border-bottom-width:1px;border-left-width:1px;border-top-style:solid;border-right-style:so