lor:rgba(20, 184, 166, 0.55);border-right-color:rgba(20, 184, 166, 0.55);border-bottom-color:rgba(20, 184, 166, 0.55);border-left-color:rgba(20, 184, 166, 0.55);box-shadow:rgba(20, 184, 166, 0.12) 0px 0px 0px 4px;}textarea{min-height:92px;resize:vertical;}footer{padding-top:26px;padding-right:0px;padding-bottom:40px;padding-left:0px;color:var(--muted);}@keyframes bounce-slow{0%, 100%{transform:translateY(0px);}50%{transform:translateY(-10px);}0%, 100%{transform:translateY(0px);}50%{transform:translateY(-10px);}0%, 100%{transform:translateY(0px);}50%{transform:translateY(-10px);}}@keyframes scroll{0%{transform:translateX(0px);}100%{transform:translateX(-50%);}}","publish":false}',replace('<body id="iphk"><header class="bg-white border-b border-gray-100 sticky top-0 z-50"><div class="max-w-7xl mx-auto px-4 sm:px-6 h-20 flex items-center justify-between"><div class="font-black text-2xl text-primary flex items-center gap-2"><span class="w-8 h-8 bg-primary text-white rounded-lg flex items-center justify-center">S</span>\n             STORE\n           </div><nav class="hidden md:flex items-center gap-8 font-medium text-gray-600"><a href="#features" class="hover:text-primary transition">ফিচার</a><a href="#reviews" class="hover:text-primary transition">রিভিউ</a><a href="#faq" class="hover:text-primary transition">প্রশ্নোত্তৰ</a></nav><a href="#order" class="bg-gray-900 text-white font-bold px-6 py-3 rounded-xl hover:bg-gray-800 transition">অর্ডার করুন</a></div></header><div class="sticky top-0 left-0 right-0 z-[60] bg-gradient-to-r from-red-600 via-red-500 to-yellow-500 py-3 shadow-lg"><div class="max-w-4xl mx-auto px-4 flex items-center justify-center gap-4 text-white"><span class="text-xl animate-pulse">⚡</span><span class="font-bold text-sm md:text-base uppercase tracking-wider">অফারটি শেষ হতে আর মাত্র:</span><div class="flex items-center gap-2 font-mono font-black text-xl md:text-2xl"><div class="bg-black/20 px-2 rounded">02</div><span class="animate-pulse">:</span><div class="bg-black/20 px-2 rounded">45</div><span class="animate-pulse">:</span><div class="bg-black/20 px-2 rounded text-yellow-300">12</div></div><span class="text-xl animate-pulse">⚡</span></div></div><section class="py-12 px-6 text-center bg-white border-b border-gray-100"><div class="max-w-4xl mx-auto"><span class="inline-block px-3 py-1 bg-amber-100 text-amber-700 text-xs font-bold rounded-full mb-4 uppercase">অফারটি সীমিত সময়ের জন্য</span><h1 class="text-3xl md:text-5xl font-extrabold text-gray-900 mb-6 leading-tight product-name">আপনার পণ্যের আকর্ষণীয় হেডলাইন এখানে লিখুন</h1><p class="text-lg text-gray-600 mb-10 max-w-2xl mx-auto">পণ্যের মূল বৈশিষ্ট্য বা কেন এটি সেরা তা ১-২ লাইনে এখানে সংক্ষেপে বর্ণনা করুন।</p><div class="mb-10"><img src="https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=800&amp;q=80" alt="Product" class="mx-auto rounded-2xl shadow-2xl max-w-full h-auto"/></div><a href="#order" class="inline-block bg-primary text-white text-xl font-bold px-12 py-5 rounded-full shadow-lg hover:opacity-90 transition transform hover:scale-105">অর্ডার করতে এখানে ক্লিক করুন</a></div></section><section class="py-12 bg-white px-4"><div class="max-w-6xl mx-auto"><h2 class="text-3xl font-bold text-center text-gray-900 mb-10">প্রোডাক্ট গ্যালারি</h2><div class="grid grid-cols-2 md:grid-cols-4 gap-4"><img src="https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=500&amp;q=80" class="rounded-xl shadow-sm hover:scale-105 transition duration-300 w-full h-48 object-cover cursor-pointer"/><img src="https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=500&amp;q=80" class="rounded-xl shadow-sm hover:scale-105 transition duration-300 w-full h-48 object-cover cursor-pointer"/><img src="https://images.unsplash.com/photo-1572635196237-14b3f281503f?w=500&amp;q=80" class="rounded-xl shadow-sm hover:scale-105 transition duration-300 w-full h-48 object-cover cursor-pointer"/><img src="https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=500&amp;q=80" class="rounded-xl shadow-sm hover:scale-105 transition duration-300 w-full h-48 object-cover cursor-pointer"/></div></div></section><div class="bg-indigo-900 text-white py-4 px-6 text-center animate-pulse"><p class="text-lg font-bold flex items-center justify-center gap-2"><span class="bg-white text-indigo-900 rounded-full w-6 h-6 flex items-center justify-center text-xs">🔥</span>\n            গত ২৪ ঘন্টায় <span class="text-yellow-400 font-black text-2xl mx-1 social-proof-count">১২৫</span> জন এই পণ্যটি অর্ডার করেছেন!\n         </p></div><section class="py-16 bg-white px-4"><div class="max-w-5xl mx-auto"><div class="text-center mb-16"><h2 class="text-3xl md:text-5xl font-black text-gray-900 mb-4">পার্থক্যটি নিজেই দেখুন</h2><div class="w-24 h-2 bg-emerald-500 mx-auto rounded-full"></div></div><div class="grid grid-cols-1 md:grid-cols-2 gap-8 items-stretch"><div class="bg-red-50/50 p-8 rounded-[3rem] border border-red-100 relative grayscale-[0.5] opacity-80"><div class="absolute -top-4 left-8 bg-red-500 text-white px-6 py-2 rounded-full font-bold shadow-lg">সাধারণ বাজারজাত পণ্য</div><div class="aspect-video bg-gray-200 rounded-3xl mb-8 overflow-hidden"><img src="https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=500&amp;q=50" class="w-full h-full object-cover"/></div><ul class="space-y-4 font-bold text-gray-500"><li class="flex items-center gap-3"><span class="text-red-500 text-2xl">❌</span> নিম্নমানের পাতলা ফেব্রিক</li><li class="flex items-center gap-3"><span class="text-red-500 text-2xl">❌</span> ধোয়ার পর রং নষ্ট হয়ে যায়</li><li class="flex items-center gap-3"><span class="text-red-500 text-2xl">❌</span> কোনো গ্যারান্টি বা ওয়ারেন্টি নেই</li><li class="flex items-center gap-3"><span class="text-red-500 text-2xl">❌</span> সাইজ ছোট-বড় হওয়ার ভয় থাকে</li></ul></div><div class="bg-emerald-50 p-8 rounded-[3rem] border-2 border-emerald-200 relative shadow-2xl shadow-emerald-200/50 transform md:scale-105"><div class="absolute -top-4 left-8 bg-emerald-600 text-white px-6 py-2 rounded-full font-bold shadow-lg">আমাদের প্রিমিয়াম পণ্য</div><div class="aspect-video bg-white rounded-3xl mb-8 overflow-hidden shadow-inner"><img src="https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=500&amp;q=80" class="w-full h-full object-cover"/></div><ul class="space-y-4 font-black text-gray-800"><li class="flex items-center gap-3"><span class="text-emerald-500 text-2xl">✅</span> ১০০% প্রিমিয়াম কটন ফেব্রিক</li><li class="flex items-center gap-3"><span class="text-emerald-500 text-2xl">✅</span> গ্যারান্টিড কালার ও টেকসই বুনন</li><li class="flex items-center gap-3"><span class="text-emerald-500 text-2xl">✅</span> ৭ দিনের মানি ব্যাক গ্যারান্টি</li><li class="flex items-center gap-3"><span class="text-emerald-500 text-2xl">✅</span> সঠিক এবং স্ট্যান্ডার্ড সাইজিং</li></ul></div></div></div></section><section class="py-12 bg-gray-50/50"><div class="max-w-6xl mx-auto px-4 grid grid-cols-2 md:grid-cols-4 gap-4 md:gap-8"><div class="bg-white/70 backdrop-blur-xl border border-white/50 p-6 rounded-3xl shadow-xl shadow-gray-200/50 text-center flex flex-col items-center gap-3 transform hover:-translate-y-2 transition duration-500"><div class="w-16 h-16 bg-emerald-50 rounded-2xl flex items-center justify-center text-emerald-600 shadow-inner"><svg fill="none" stroke="currentColor" viewBox="0 0 24 24" class="w-8 h-8"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M5 13l4 4L19 7"></path></svg></div><h3 class="font-black text-gray-900 leading-tight">দ্রুত ডেলিভারি</h3><p class="text-xs text-gray-500 font-bold uppercase tracking-tighter">সারা বাংলাদেশে</p></div><div class="bg-white/70 backdrop-blur-xl border border-white/50 p-6 rounded-3xl shadow-xl shadow-gray-200/50 text-center flex flex-col items-center gap-3 transform hover:-translate-y-2 transition duration-500"><div class="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 shadow-inner"><svg fill="none" stroke="currentColor" viewBox="0 0 