INSERT INTO "visitor_messages" VALUES(16,3,'assistant',replace('\nআমাদের Ozzyl প্ল্যাটফর্ম বেছে নেবার কারণ হলো:\n\n✅ বাংলাদেশের দ্রুততম e-commerce platform (Cloudflare CDN)\n✅ কোনো টেকনিক্যাল জ্ঞান ছাড়াই ১০ মিনিটে স্টোর তৈরি\n✅ এক্টিভ মার্চেন্টদের 500+ রিভিউএ ৫ তারকা রেটিং\n✅ বিকাশ/নগদে পেমেন্ট সরাসরি আপনার একাউন্টে\n\nএক্টাউন্ট খুলে এখনই শুরু করুন: https://ozzyl.com/signup  \nনেয়া কোন অসুবিধা হলে জানান, আমি সাহায্য করব! 😊','\n',char(10)),1770165847);
