INSERT INTO "visitor_messages" VALUES(23,3,'assistant',replace('আমাদের ৩টি প্যাকেজ আছে:\n\n**Free (৳0/মাস)** - 5টি প্রোডাক্ট, 50 অর্ডার/মাস, Landing Page\n**Starter (৳499/মাস)** - 50টি প্রোডাক্ট, 500 অর্ডার/মাস, Full Store + বিকাশ/নগদ\n**Premium (৳1999/মাস)** - 200টি প্রোডাক্ট, 3000 অর্ডার/মাস, কাস্টম ডোমেইন + কুরিয়ার Integration\n\nকোনটা আপনার জন্য ভালো হবে বলে মনে হয়? 😊','\n',char(10)),1770469560);
